INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '25a3a14b-f196-42b9-8975-683647563f48',
  '00000000-0000-0000-0000-000000000001',
  $escape$SolidJS Forms — Controlled Signals, Uncontrolled Refs, and Modular Forms + Zod$escape$,
  $escape$SolidJS controlled forms bind a signal directly to an input: `value={name()}` + `onInput={e => setName(e.target.value)}`. Unlike React, this doesn't re-render a component — SolidJS surgically updates only that DOM node. Uncontrolled forms skip signals entirely: declare `let ref!: HTMLInputElement`, attach with `<input ref={ref} />`, and read `ref.value` on submit. Prefer uncontrolled when you only need values at submission time and want zero reactive overhead.

For complex forms with validation, reach for `@modular-forms/solid` — the SolidJS-native answer to React Hook Form. It uses stores (not signals) internally, so each field update is granular. Pair it with a Zod schema via `zodForm()` adapter for type-safe validation. Field components use `<Field>` with a render prop exposing `field` (value, error) and `props` (spread onto your input). The `handleSubmit` wrapper calls your action only after Zod passes — no manual `.safeParse()` needed. Crucially, the form store is reactive: `form.invalid` and `form.dirty` are live, so you can gate your submit button with `<Show when={!form.invalid}>` without any extra state.$escape$,
  $escape$import { createForm, zodForm } from '@modular-forms/solid';
import { Field, Form } from '@modular-forms/solid';
import { z } from 'zod';

const LoginSchema = z.object({
  email: z.string().email(),
  password: z.string().min(8),
});
type LoginForm = z.infer<typeof LoginSchema>;

export function LoginForm() {
  const [form, { Form, Field }] = createForm<LoginForm>({
    validate: zodForm(LoginSchema),
  });

  return (
    <Form onSubmit={(values) => console.log(values)}>
      <Field name="email">
        {(field, props) => (
          <>
            <input {...props} type="email" value={field.value ?? ''} />
            {field.error && <span>{field.error}</span>}
          </>
        )}
      </Field>
      <button type="submit" disabled={form.invalid}>Login</button>
    </Form>
  );
}$escape$,
  $escape$typescript$escape$,
