INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b5416a99-0220-4d39-bc59-e433441cbae0',
  '00000000-0000-0000-0000-000000000001',
  $escape$SolidJS Prop Typing — Discriminated Unions for Bulletproof Component Variants$escape$,
  $escape$SolidJS components receive props as a single reactive object, so TypeScript types must account for Solid's `JSX.Element` return and its accessor-based reactivity. For variant components — buttons, alerts, badges — discriminated unions eliminate runtime guesswork and enforce exhaustive handling at compile time.

Define a union on a `kind` literal, then use a type-narrowed `switch` inside a `<Show>` or direct JSX conditional. Avoid `any` on props entirely; if an external value is untyped, cast it at the boundary with a validated type guard, not inline `as any`.

Crucial Solid-specific detail: destructuring props breaks reactivity. Use `props.kind`, never `const { kind } = props`. If you need local aliases, use `splitProps` from `solid-js`, which preserves the reactive proxy. This keeps variant logic reactive — if a parent signal changes `kind`, the component re-evaluates correctly without a full re-render cycle, because Solid tracks fine-grained signal reads, not component-level diffing.$escape$,
  $escape$import { splitProps, Component, JSX } from 'solid-js';

type ButtonProps =
  | { kind: 'primary'; onClick: () => void; label: string }
  | { kind: 'danger'; onConfirm: () => void; label: string; confirmText: string };

const Button: Component<ButtonProps> = (props) => {
  const [local, rest] = splitProps(props, ['kind', 'label']);

  if (local.kind === 'primary') {
    return <button onClick={(props as Extract<ButtonProps, { kind: 'primary' }>).onClick}>{local.label}</button>;
  }

  const p = props as Extract<ButtonProps, { kind: 'danger' }>;
  return (
    <button onClick={p.onConfirm} title={p.confirmText}>
      {local.label}
    </button>
  );
};$escape$,
  $escape$typescript$escape$,
