INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a47b065a-26a3-4555-b93d-27c78c0bc766',
  '00000000-0000-0000-0000-000000000001',
  $escape$SolidJS Security — innerHTML, Token Storage, and Input Sanitization$escape$,
  $escape$Unlike React's `dangerouslySetInnerHTML`, SolidJS accepts `innerHTML` directly as a prop with no ceremony — no warning, no friction. That silence is the danger. `<div innerHTML={userContent} />` executes any script tags or event handlers embedded in `userContent` verbatim. Always sanitize before binding. DOMPurify integrates cleanly: wrap raw HTML in `createMemo` so sanitization reruns reactively whenever the signal updates, not on every render tick. For token storage, avoid `localStorage` — it's readable by any injected script. Prefer `httpOnly` cookies managed server-side. If you must store client-side state (e.g. CSRF tokens), use a SolidJS `createStore` scoped to a short session and clear it on `onCleanup`. For form inputs, never pass `event.target.value` directly into a `createSignal` that feeds an `innerHTML` binding. Treat the signal as a trust boundary: sanitize at write time, not read time, so downstream derivations (createMemo, createEffect) always consume clean data.$escape$,
  $escape$import DOMPurify from 'dompurify';
import { createSignal, createMemo, onCleanup } from 'solid-js';

function SafeRenderer() {
  const [raw, setRaw] = createSignal('');

  // Sanitize reactively — runs only when `raw` changes
  const clean = createMemo(() => DOMPurify.sanitize(raw()));

  onCleanup(() => setRaw(''));

  return (
    <>
      <input onInput={(e) => setRaw(e.currentTarget.value)} />
      {/* Safe: bind the memo, never the raw signal */}
      <div innerHTML={clean()} />
    </>
  );
}$escape$,
  $escape$typescript$escape$,
