INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'c1da2dfb-6b7b-428d-a582-6f98ed57e9c2',
  '00000000-0000-0000-0000-000000000001',
  $escape$SolidJS Memory Leaks — Mastering onCleanup for Effects, Fetches, and Events$escape$,
  $escape$SolidJS's `onCleanup()` is the single cleanup primitive for all reactive scopes — it runs before an effect re-executes and when a component's owner is disposed. Unlike React's `useEffect` return function or Vue's `onUnmounted`, `onCleanup` can be called anywhere inside a reactive owner, not just the root of an effect.

The most common leaks come from three sources: dangling event listeners, unaborted fetches, and uncleared timers. SolidJS's fine-grained reactivity means a `createEffect` watching a signal re-runs on every change — without `onCleanup`, each run spawns a new `AbortController` while the previous one lingers.

Call `onCleanup` at the top of `createEffect` to register teardown before any async work begins. For imperative `addEventListener` calls inside `createEffect` or `onMount`, always pair them with `removeEventListener` in a corresponding `onCleanup`. In `onMount`, the cleanup registered via `onCleanup` fires on component disposal.

Signals and stores owned by a component are automatically disposed when the component unmounts — but external side-effects like fetch requests, WebSocket connections, and timers are yours to clean up.$escape$,
  $escape$import { createEffect, createSignal, onMount, onCleanup } from "solid-js";

function LiveSearch() {
  const [query, setQuery] = createSignal("");

  createEffect(() => {
    const ctrl = new AbortController();
    onCleanup(() => ctrl.abort());
    fetch(`/api/search?q=${query()}`, { signal: ctrl.signal })
      .then(r => r.json())
      .catch(e => { if (e.name !== "AbortError") throw e; });
  });

  onMount(() => {
    const handler = (e: KeyboardEvent) => setQuery(e.key);
    window.addEventListener("keydown", handler);
    onCleanup(() => window.removeEventListener("keydown", handler));
  });
}$escape$,
