INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '0a32e2f6-d817-4e0d-979c-9dbd435496f0',
  '00000000-0000-0000-0000-000000000001',
  $escape$SolidJS Config — Validate Vite Env Vars at Startup with Zod$escape$,
  $escape$SolidJS apps built with Vite expose env vars via `import.meta.env`, but nothing stops a mis-named var from silently becoming `undefined` at runtime. Validate the entire env contract once at module load time using Zod — before any component mounts or any `createResource` fires.

Define a schema in `src/env.ts` and parse `import.meta.env` eagerly. Zod's `z.string().url()` rejects malformed API base URLs immediately; `z.string().min(1)` catches empty-string substitutions that Vite happily injects. Because this module is imported before `render()` in `src/index.tsx`, a bad config throws before the SolidJS reactive graph even initialises — no partial hydration, no cryptic fetch errors mid-session.

Export the typed `env` object and import it wherever you'd otherwise reach for `import.meta.env.VITE_*` directly. Signals and resources that depend on `env.VITE_API_URL` now get a guaranteed `string`, not `string | undefined`, so TypeScript stops asking you to null-check every call site.$escape$,
  $escape$// src/env.ts
import { z } from 'zod';

const schema = z.object({
  VITE_API_URL: z.string().url(),
  VITE_WS_URL: z.string().url(),
  VITE_APP_ENV: z.enum(['development', 'staging', 'production']),
});

export const env = schema.parse(import.meta.env);

// src/index.tsx
import './env';           // throws here if invalid — before render()
import { render } from 'solid-js/web';
import App from './App';

render(() => <App />, document.getElementById('root')!);$escape$,
  $escape$typescript$escape$,
