INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '5a6aa5ac-c2a5-4e9b-9039-dbc4aa6701fe',
  '00000000-0000-0000-0000-000000000001',
  $escape$SolidJS Animation — CSS for States, Framer Motion for Sequences, and Respecting prefers-reduced-motion$escape$,
  $escape$SolidJS's fine-grained reactivity makes animation straightforward: CSS handles simple state transitions via class toggling with `classList`, while Framer Motion's `motion` primitives cover complex sequences. Because SolidJS doesn't batch renders like React, transitions fire immediately when signals update — no stale-closure surprises.

For reduced-motion, read the media query once at module scope using `window.matchMedia`, or reactively via a `createSignal` tied to the `change` event. Pass this as a prop or context to conditionally swap `animate` configs in Framer Motion, or strip transition classes entirely.

Avoid wrapping every element in a `<motion.div>` — SolidJS's DOM diffing is minimal by design, so unnecessary wrappers break that contract. Prefer animating existing DOM nodes with `ref` + the Web Animations API for surgical control, or use `@motionone/solid` (the official SolidJS binding) instead of the React-targeted `framer-motion` package.$escape$,
  $escape$import { createSignal, onMount } from 'solid-js';
import { Motion } from '@motionone/solid';

const prefersReduced = window.matchMedia('(prefers-reduced-motion: reduce)').matches;

export function Card() {
  const [active, setActive] = createSignal(false);

  return (
    <Motion.div
      animate={prefersReduced ? {} : { scale: active() ? 1.05 : 1 }}
      transition={{ duration: 0.2 }}
      classList={{ 'bg-blue-500': active() }}
      onClick={() => setActive(a => !a)}
    >
      Click me
    </Motion.div>
  );
}$escape$,
  $escape$typescript$escape$,
