INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '395b31ed-bf26-406f-88bc-33440db5a5e9',
  '00000000-0000-0000-0000-000000000001',
  $escape$solidjs Production Monitoring — Sentry, Web Vitals, and Source Maps$escape$,
  $escape$solidjs apps use `@sentry/solidjs`, which wraps `@sentry/browser` with reactive-runtime awareness. Call `Sentry.init()` in `main.tsx` before `render()` — initializing after mount misses early reactive panics. For router-aware tracing with `@solidjs/router`, pass `withSentryRouterWrapper` to the `root` prop of `<Router>`.

Capture UI errors via solidjs's `<ErrorBoundary>` — its `fallback` prop receives `(err, reset)`, so call `Sentry.captureException(err)` there directly. Reactive computations that throw inside `createEffect` or `createMemo` propagate to the nearest `<ErrorBoundary>`, meaning a single boundary at the app root catches most reactive panics without per-component wiring.

For Web Vitals, wire `web-vitals` callbacks in `main.tsx` and forward via `Sentry.captureEvent`. Use `level: "info"` to keep them separate from error counts in your Sentry dashboard.

Source maps: set `build.sourcemap: true` in `vite.config.ts` and add `@sentry/vite-plugin`. The plugin uploads maps at build time and strips them from the production bundle — stack traces stay readable in Sentry without exposing source to clients.$escape$,
  $escape$// main.tsx — Sentry.init() must run before render()
import * as Sentry from "@sentry/solidjs";
import { onLCP, onCLS, onINP } from "web-vitals";

Sentry.init({
  dsn: import.meta.env.VITE_SENTRY_DSN,
  integrations: [Sentry.browserTracingIntegration()],
  tracesSampleRate: 0.1,
  environment: import.meta.env.MODE,
});

[onLCP, onCLS, onINP].forEach((fn) =>
  fn(({ name, value }) =>
    Sentry.captureEvent({ message: `vital:${name}`, level: "info", extra: { value } })
  )
);$escape$,
