INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '4dd35abb-3005-4f29-b11d-ff82f31ebe78',
  '00000000-0000-0000-0000-000000000001',
  $escape$SolidJS Reactivity — Why Your Component Runs Once but Your UI Keeps Updating$escape$,
  $escape$React re-runs the entire component function on every state change. Vue wraps state in ES Proxies and tracks mutations at runtime. Svelte rewrites your source at compile time, inserting `$$invalidate` calls. SolidJS does none of these.

In Solid, components are setup functions — they execute exactly once. Reactivity is owned by signals, not components. `createSignal` returns a getter/setter pair; the getter is a tracked reactive read. When you call `setCount(5)`, Solid's runtime walks the signal's subscriber graph and surgically updates only the DOM nodes that called `count()` — no reconciler, no VDOM diffing, no stale closure risk.

`createEffect` subscribes automatically to every signal accessed during its execution and re-runs when any of them change. `createMemo` is a lazy, cached derivation — it recomputes only when its signal dependencies change, not on a render cycle (there is no render cycle). This makes deeply nested derived state cheap by default.

The mental model shift: stop thinking in renders. Think in subscriptions. A Solid app is a reactive graph where signals push updates downstream through effects and memos directly to the DOM.$escape$,
  $escape$import { createSignal, createEffect, createMemo } from "solid-js";

function Counter() {
  // Counter() itself never runs again after mount
  const [count, setCount] = createSignal(0);
  const doubled = createMemo(() => count() * 2); // cached, not recalculated on renders

  createEffect(() => {
    // auto-subscribes to count(); re-runs only when count() changes
    console.log("count is now:", count());
  });

  return (
    <button onClick={() => setCount(c => c + 1)}>
      {count()} × 2 = {doubled()}
    </button>
  );
}$escape$,
  $escape$javascript$escape$,
